import numpy as np

class GradientAccumulator:
    def __init__(self, optimizer, accumulate_steps: int = 4):
        self.optimizer = optimizer
        self.accumulate_steps = accumulate_steps
        self.accumulated = None
        self.count = 0

    def step(self, params: list[np.ndarray], grads: list[np.ndarray]) -> bool:
        if self.accumulated is None:
            self.accumulated = [np.zeros_like(g) for g in grads]
        for acc, g in zip(self.accumulated, grads):
            acc += g / self.accumulate_steps
        self.count += 1
        if self.count >= self.accumulate_steps:
            self.optimizer.step(params, self.accumulated)
            self.accumulated = None
            self.count = 0
            return True
        return False
